sql:
SELECT ancestor_name
FROM ancestors
WHERE birth_place = 'England';

SELECT COUNT(kit_id) AS kit_count
FROM dna_kits
WHERE user_id = 1;

SELECT COUNT(*) AS member_count
FROM group_members
WHERE group_id = 1;

SELECT migration_path
FROM dna_migrations
WHERE kit_id = 1;

SELECT AVG(CAST(SUBSTR(birth_date, 1, 4) AS INTEGER)) AS average_birth_year
FROM ancestors
WHERE birth_date IS NOT NULL;

SELECT relationship
FROM relative_links
WHERE relative_id = 1;

SELECT relationship
FROM relative_links
WHERE link_id = 0;
